  SELECT l.*, ROW_NUMBER() OVER (
    PARTITION BY lead_id
    ORDER BY updated_at DESC) rn
  FROM lead_events l
) t WHERE rn = 1;

def bucket(amount, high=800000):
    if amount >= high:
        return "premium"
    return "standard"

